# OEIS sequence: A087980

from itertools import islice
from heapq import heappop, heappush
from sympy import factorint, prevprime, nextprime
def A087980_gen(): # generator of terms if the first n terms are desired
    h, hset = [1], {1}
    while True:
        yield (m:=heappop(h))
        ps = factorint(m)
        for p in ps:
            if p == 2 or ps[prevprime(p)]>ps[p]+1:
                mp = m*p
                if mp not in hset:
                    heappush(h,mp)
                    hset.add(mp)
        if m==1:
            heappush(h,2)
            hset.add(2)
        elif ps[a:=max(ps.keys())] > 1:
            mp = m*nextprime(a)
            if mp not in hset:
                heappush(h,mp)
                hset.add(mp)
A087980_list =  list(islice(A087980_gen(),100)) # _Chai Wah Wu_, Mar 23 2026

